1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	const BLOCK_SIZE = 3;
15	const BLOCK_PREMIUM = 60;
16	
17	function countByType(items: any[]): Record<string, number> {
18	  const counts: Record<string, number> = {};
19	  for (const item of items) {
20	    counts[item.type] = (counts[item.type] ?? 0) + 1;
21	  }
22	  return counts;
23	}
24	
25	function calculateBasePremium(typeCounts: Record<string, number>): number {
26	  let total = 0;
27	  for (const [type, count] of Object.entries(typeCounts)) {
28	    if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
29	      total += BLOCK_PREMIUM;
30	    } else {
31	      total += count * (BASE_PREMIUM[type] ?? 0);
32	    }
33	  }
34	  return total;
35	}
36	
37	const CURSED_SURCHARGE_RATE = 0.5;
38	
39	function calculateItemSurcharges(items: any[]): number {
40	  let total = 0;
41	  for (const item of items) {
42	    if (item.cursed) {
43	      total += (BASE_PREMIUM[item.type] ?? 0) * CURSED_SURCHARGE_RATE;
44	    }
45	  }
46	  return total;
47	}
48	
49	function calculateQuotePremium(items: any[]): number {
50	  const typeCounts = countByType(items);
51	  const basePremium = calculateBasePremium(typeCounts);
52	  const itemSurcharges = calculateItemSurcharges(items);
53	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
54	  return Math.ceil(basePremium + itemSurcharges + firstInsurance + PROCESSING_FEE);
55	}
56	
57	export function processScenario(scenario: any): unknown {
58	  const results = scenario.steps.map((step: any) => ({
59	    premium: calculateQuotePremium(step.items),
60	  }));
61	
62	  return { results };
63	}
